1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type Damage = { itemType: string; amount: number };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: Customer; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE = 0.1;
14	const CURSE_SURCHARGE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT = 0.2;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
20	
21	const BASE_PREMIUM: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const DEDUCTIBLE = 100;
40	const CAP_MULTIPLIER = 2;
41	const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
42	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const BLOCK_SIZE = 3;
46	const BLOCK_PREMIUM = 60;
47	
48	const isBlock = (type: string, count: number): boolean =>
49	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
50	
51	const groupPremium = (type: string, count: number): number =>
52	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
53	
54	const tally = <T>(values: Iterable<T>, key: (v: T) => string): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const v of values) {
57	    const k = key(v);
58	    counts.set(k, (counts.get(k) ?? 0) + 1);
59	  }
60	  return counts;
61	};
62	
63	const countByType = (items: Item[]): Map<string, number> =>
64	  tally(items, (i) => i.type);
65	
66	const sumBasePremiumsByGroup = (items: Item[]): number =>
67	  [...countByType(items)].reduce(
68	    (total, [type, count]) => total + groupPremium(type, count),
69	    0,
70	  );
71	
72	const isCursed = (item: Item): boolean => item.cursed === true;
73	const isHighlyEnchanted = (item: Item): boolean =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
75	const isLoyalCustomer = (customer: Customer): boolean =>
76	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
77	
78	const surchargeRateFor = (item: Item): number =>
79	  (isCursed(item) ? CURSE_SURCHARGE : 0)
80	  + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
81	
82	const perItemSurcharges = (items: Item[]): number =>
83	  items.reduce(
84	    (total, item) => total + BASE_PREMIUM[item.type] * surchargeRateFor(item),
85	    0,
86	  );
87	
88	const rateIf = (condition: boolean, rate: number): number =>
89	  condition ? rate : 0;
90	
91	const policyWideAdjustments = (
92	  policyBase: number,
93	  customer: Customer,
94	  isFollowUp: boolean,
95	): number => {
96	  const netRate =
97	    FIRST_INSURANCE_SURCHARGE
98	    - rateIf(isLoyalCustomer(customer), LOYALTY_DISCOUNT)
99	    - rateIf(isFollowUp, FOLLOWUP_CONTRACT_DISCOUNT);
100	  return policyBase * netRate;
101	};
102	
103	const quotePremiumFor = (
104	  customer: Customer,
105	  { items }: QuoteStep,
106	  isFollowUp: boolean,
107	): QuoteResult => {
108	  const policyBase = sumBasePremiumsByGroup(items);
109	  const total =
110	    policyBase
111	    + perItemSurcharges(items)
112	    + policyWideAdjustments(policyBase, customer, isFollowUp)
113	    + PROCESSING_FEE;
114	  return { premium: Math.ceil(total) };
115	};
116	
117	type Policy = { items: Item[]; remainingCap: number };
118	
119	const insuranceSumFor = (items: Item[]): number =>
120	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
121	
122	const assertKnownItemTypes = (items: Item[]): void => {
123	  for (const { type } of items) {
124	    if (!(type in BASE_PREMIUM)) throw new Error(`Unknown item type: ${type}`);
125	  }
126	};
127	
128	const createPolicy = ({ items }: QuoteStep): Policy => {
129	  assertKnownItemTypes(items);
130	  return { items, remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER };
131	};
132	
133	const reimbursementRateFor = (item: Item): number =>
134	  (item.enchantment ?? 0) >= REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD
135	    ? HIGH_ENCHANTMENT_REIMBURSEMENT
136	    : 1;
137	
138	const findItem = (policy: Policy, itemType: string): Item => {
139	  const item = policy.items.find((i) => i.type === itemType);
140	  if (item === undefined) throw new Error(`Item not in policy: ${itemType}`);
141	  return item;
142	};
143	
144	const payoutForDamage = (policy: Policy, damage: Damage): number => {
145	  const item = findItem(policy, damage.itemType);
146	  const reimbursed = damage.amount * reimbursementRateFor(item);
147	  return Math.max(0, reimbursed - DEDUCTIBLE);
148	};
149	
150	const totalPayout = (policy: Policy, damages: Damage[]): number =>
151	  damages.reduce((sum, d) => sum + payoutForDamage(policy, d), 0);
152	
153	const capAndRoundDown = (amount: number, cap: number): number =>
154	  Math.floor(Math.min(amount, cap));
155	
156	const assertDamagesFitPolicy = (policy: Policy, damages: Damage[]): void => {
157	  const policyCounts = countByType(policy.items);
158	  const damageCounts = tally(damages, (d) => d.itemType);
159	  for (const [itemType, count] of damageCounts) {
160	    if (count > (policyCounts.get(itemType) ?? 0)) {
161	      throw new Error(`More damage entries for ${itemType} than policy covers`);
162	    }
163	  }
164	};
165	
166	const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
167	  assertDamagesFitPolicy(policy, incident.damages);
168	  const uncapped = totalPayout(policy, incident.damages);
169	  const payout = capAndRoundDown(uncapped, policy.remainingCap);
170	  policy.remainingCap -= payout;
171	  return { payout, remainingCap: policy.remainingCap };
172	};
173	
174	export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
175	  const policies: Policy[] = [];
176	  const handle = (step: Step): StepResult => {
177	    if (step.op === "quote") {
178	      const isFollowUp = policies.length > 0;
179	      policies.push(createPolicy(step));
180	      return quotePremiumFor(customer, step, isFollowUp);
181	    }
182	    return settleClaim(policies[step.policy], step);
183	  };
184	  return { results: steps.map(handle) };
185	};
